det_check_template:
proof fn det_new<V, Pred: RwLockPredicate<V>>(val: V, pred: Pred, r1: RwLock<V, Pred>, r2: RwLock<V, Pred>)
    requires (pred.inv(val)),
    ensures
        ({
            &&& (r1.pred() == pred)
            &&& (r2.pred() == pred)
        }) ==> det_new_equal::<V, Pred>(r1, r2),
{
    reveal(pred);
{ASSUMES}}

equal_fn_def:
// Generated equal-fn for determinism check.
// Policy: errs_equivalent=True, opaque_ok=False
spec fn det_new_equal<V, Pred: RwLockPredicate<V>>(r1: RwLock<V, Pred>, r2: RwLock<V, Pred>) -> bool {
    (r1 == r2)
}
